// Generates one vitest test file per `.md` scenario so that each scenario file
// shows up as its own group in the test report (the default vitest reporter
// groups by test file) and can run in a separate worker. Run after adding or
// renaming a scenario:
//
//   pnpm gen:scenario-suites
//
// The generated files live in test/unittest/scenario-suites/ and are checked
// in. `scenario-suites.guard.test.ts` fails if they drift from the .md set.

import { existsSync, mkdirSync, readdirSync, rmSync, writeFileSync } from "fs";
import path from "path";
import { fileURLToPath } from "url";

const here = path.dirname(fileURLToPath(import.meta.url));
const SCENARIOS_DIR = path.join(here, "scenarios");
const SUITES_DIR = path.join(here, "scenario-suites");

/** Returns the base names (without extension) of every scenario `.md` file. */
export function listScenarioNames() {
  return readdirSync(SCENARIOS_DIR)
    .filter((f) => f.endsWith(".md"))
    .map((f) => f.slice(0, -".md".length))
    .sort();
}

export function suiteFileContent(name) {
  return `// Generated by \`pnpm gen:scenario-suites\`. Do not edit by hand.
import { resolvePath } from "@typespec/compiler";
import { describeScenarioFile } from "../scenario-runner.js";

describeScenarioFile(resolvePath(import.meta.dirname, "../scenarios/${name}.md"));
`;
}

function main() {
  if (!existsSync(SUITES_DIR)) {
    mkdirSync(SUITES_DIR, { recursive: true });
  }
  for (const file of readdirSync(SUITES_DIR)) {
    if (file.endsWith(".test.ts")) {
      rmSync(path.join(SUITES_DIR, file));
    }
  }
  const names = listScenarioNames();
  for (const name of names) {
    writeFileSync(path.join(SUITES_DIR, `${name}.test.ts`), suiteFileContent(name));
  }
  // eslint-disable-next-line no-console
  console.log(`Generated ${names.length} scenario suite file(s) in ${SUITES_DIR}`);
}

if (
  import.meta.url === `file://${process.argv[1]}` ||
  process.argv[1] === fileURLToPath(import.meta.url)
) {
  main();
}
